% Define model
ft = fittype('A*exp(-k*x) + C', ...
    'independent', 'x', 'coefficients', {'A', 'k', 'C'});
opts = fitoptions(ft);

% Fit options (set reasonable starting points!)
A0 = y(1) - y(end);                % Initial amplitude = initial - baseline
k0 = 1 / (t(end) - t(1));          % Guess: decay rate ~ inverse of time span
C0 = y(end);                       % Baseline level after decay
opts.StartPoint = [A0, k0, C0];

% Do the fit
[fitresult, gof] = fit(t', y', ft, opts);

% Check results
disp(fitresult)

% Get fitted parameters
A = fitresult.A;
k = fitresult.k;
C = fitresult.C;

% Correct the data
t_cont = [min(t):max(t)];
decay_curve_allt = A * exp(-k * t_cont) + C;
decay_curve = A * exp(-k * t) + C;
y_corrected = y .* (decay_curve(1) ./ decay_curve);

% Plot to check
figure;
plot(t, y, 'o', 'DisplayName', 'Measured');
hold on;
plot(t_cont, decay_curve_allt, '-', 'DisplayName', 'Fit Curve');
plot(t, y_corrected, 'x', 'DisplayName', 'Corrected');
legend show
xlabel('Rank')
ylabel('Value')
